    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AppServerLifecycleState {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        case 1: return .stopped

        case 2: return .starting

        case 3: return .ready

        case 4: return .degraded

        case 5: return .failed

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AppServerLifecycleState, into buf: inout [UInt8]) {
        switch value {

        case .stopped:
            writeInt(&buf, Int32(1))

        case .starting:
            writeInt(&buf, Int32(2))

        case .ready:
            writeInt(&buf, Int32(3))

        case .degraded:
            writeInt(&buf, Int32(4))

        case .failed:
            writeInt(&buf, Int32(5))

        }
    }
